// Custom AnimInstance in C++
UCLASS()
class UMyAnimInstance : public UAnimInstance {
    GENERATED_BODY()
public:
    UPROPERTY(BlueprintReadOnly, Category="Movement")
    float Speed;

    UPROPERTY(BlueprintReadOnly, Category="Movement")
    bool bIsInAir;

    UPROPERTY(BlueprintReadOnly, Category="Movement")
    float Direction;

    virtual void NativeUpdateAnimation(float DeltaSeconds) override {
        APawn* Pawn = TryGetPawnOwner();
        if (!Pawn) return;

        Speed = Pawn->GetVelocity().Size();
        bIsInAir = Pawn->GetMovementComponent()->IsFalling();
        Direction = CalculateDirection(Pawn->GetVelocity(), Pawn->GetActorRotation());
    }
};

// Play attack montage
void AMyCharacter::Attack() {
    if (UAnimInstance* Anim = GetMesh()->GetAnimInstance()) {
        float Duration = Anim->Montage_Play(AttackMontage, 1.0f);

        // Get notified when it ends
        FOnMontageEnded EndDelegate;
        EndDelegate.BindUObject(this, &AMyCharacter::OnAttackEnd);
        Anim->Montage_SetEndDelegate(EndDelegate, AttackMontage);
    }
}

void AMyCharacter::OnAttackEnd(UAnimMontage* Montage, bool bInterrupted) {
    bIsAttacking = false;
    if (!bInterrupted) {
        // Attack completed successfully
    }
}

// Combo system — jump to next section
void AMyCharacter::ComboNext() {
    if (UAnimInstance* Anim = GetMesh()->GetAnimInstance()) {
        Anim->Montage_JumpToSection(TEXT("Combo2"), AttackMontage);
    }
}

// Custom AnimNotify for spawning a projectile at the right frame
UCLASS()
class UAnimNotify_SpawnProjectile : public UAnimNotify {
    GENERATED_BODY()
public:
    UPROPERTY(EditAnywhere)
    TSubclassOf<AProjectile> ProjectileClass;

    UPROPERTY(EditAnywhere)
    FName SocketName = TEXT("Muzzle");

    virtual void Notify(USkeletalMeshComponent* MeshComp,
        UAnimSequenceBase* Animation, const FAnimNotifyEventReference& EventRef) override {

        AActor* Owner = MeshComp->GetOwner();
        if (!Owner || !ProjectileClass) return;

        FVector Loc = MeshComp->GetSocketLocation(SocketName);
        FRotator Rot = MeshComp->GetSocketRotation(SocketName);
        Owner->GetWorld()->SpawnActor<AProjectile>(ProjectileClass, Loc, Rot);
    }
};

// AnimNotifyState for melee damage window
UCLASS()
class UAnimNotifyState_MeleeWindow : public UAnimNotifyState {
    GENERATED_BODY()
public:
    virtual void NotifyBegin(USkeletalMeshComponent* MeshComp, UAnimSequenceBase* Anim, float TotalDuration, const FAnimNotifyEventReference& EventRef) override {
        if (AMyCharacter* Char = Cast<AMyCharacter>(MeshComp->GetOwner()))
            Char->EnableWeaponCollision(true);
    }
    virtual void NotifyEnd(USkeletalMeshComponent* MeshComp, UAnimSequenceBase* Anim, const FAnimNotifyEventReference& EventRef) override {
        if (AMyCharacter* Char = Cast<AMyCharacter>(MeshComp->GetOwner()))
            Char->EnableWeaponCollision(false);
    }
};

// Setting up variables for a 2D blend space in AnimInstance
virtual void NativeUpdateAnimation(float DeltaSeconds) override {
    APawn* Pawn = TryGetPawnOwner();
    if (!Pawn) return;

    // Speed for blend space X or Y axis
    FVector Velocity = Pawn->GetVelocity();
    Speed = Velocity.Size2D(); // horizontal speed only

    // Direction for 8-way blend space (-180 to 180)
    Direction = CalculateDirection(Velocity, Pawn->GetActorRotation());

    // These variables feed into the BlendSpace node in the AnimGraph
}

// Typical 2D Blend Space layout:
// Direction: -180 to 180 (left, forward, right, backward)
// Speed: 0 to 600
// Samples: Idle(0,0), WalkFwd(150,0), RunFwd(600,0),
//          WalkLeft(150,-90), RunLeft(600,-90), etc.

// Attach weapon to character's hand socket
void AMyCharacter::EquipWeapon(AWeapon* Weapon) {
    Weapon->AttachToComponent(
        GetMesh(),
        FAttachmentTransformRules::SnapToTargetNotIncludingScale,
        TEXT("weapon_r")  // Socket name
    );
}

// Spawn muzzle flash at socket
void AMyWeapon::Fire() {
    FVector MuzzleLoc = WeaponMesh->GetSocketLocation(TEXT("Muzzle"));
    FRotator MuzzleRot = WeaponMesh->GetSocketRotation(TEXT("Muzzle"));
    UGameplayStatics::SpawnEmitterAtLocation(GetWorld(), MuzzleFlashFX, MuzzleLoc, MuzzleRot);
}
